INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9f91dc7d-bab8-42c1-ab8e-12793917be32',
  '00000000-0000-0000-0000-000000000001',
  $escape$OpenAI API Prompt Engineering — System Prompts, Few-Shot, CoT, and Structured Output$escape$,
  $escape$The OpenAI API exposes four prompt engineering levers that compound when combined. The `system` message in the `messages` array sets persistent persona and constraints — it survives across turns and outranks user instructions in practice. Few-shot examples belong in `user`/`assistant` message pairs before the real query; placing them in `system` wastes tokens and loses the turn-alternation signal the model was fine-tuned on. Chain-of-thought is triggered by appending "Think step by step" to the user message or by adding an empty `assistant` prefill like `{"role": "assistant", "content": "Let me reason through this:"}` — this forces scratchpad output before the answer. For structured output, use `response_format: { type: "json_schema", json_schema: { ... } }` with `gpt-4o` or later; this guarantees schema-valid JSON via constrained decoding, unlike prompt-only JSON requests which can hallucinate keys. Combine all four: system sets rules, few-shot calibrates style, CoT improves reasoning accuracy, and `json_schema` locks the output contract.$escape$,
  $escape$import OpenAI from "openai";

const client = new OpenAI();

const response = await client.chat.completions.create({
  model: "gpt-4o",
  messages: [
    { role: "system", content: "You are a code reviewer. Be concise and critical." },
    { role: "user", content: "Review this function.\n```js\nfunction add(a,b){return a+b}\n```" },
    { role: "assistant", content: "{ \"issues\": [\"No type validation\"], \"rating\": 6 }" },
    { role: "user", content: "Review this.\n```js\nasync function fetchUser(id){return await db.find(id)}\n```\nThink step by step." },
  ],
  response_format: {
    type: "json_schema",
    json_schema: {
      name: "review",
      schema: {
        type: "object",
        properties: {
          issues: { type: "array", items: { type: "string" } },
          rating: { type: "number" }
        },
        required: ["issues", "rating"],
        additionalProperties: false
      },
      strict: true
    }
  }
});

console.log(JSON.parse(response.choices[0].message.content!));$escape$,
