INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9b344ca1-83e2-46ce-a7ec-99c761cf4a54',
  '00000000-0000-0000-0000-000000000001',
  $escape$openai_api + LangChain LCEL — Composing Chains, Agents, and Memory with ChatOpenAI$escape$,
  $escape$LCEL's pipe operator (`|`) chains Runnables — each step transforms the dict passed through it. `ChatOpenAI(model="gpt-4o")` wraps OpenAI's Chat Completions endpoint and returns an `AIMessage`; pipe it into `StrOutputParser()` to extract `.content` automatically. For agents, `llm.bind_tools(tools)` serializes your `@tool`-decorated Python functions into OpenAI's native `tools` parameter and routes `tool_calls` back to them via `AgentExecutor` — no manual JSON schema writing. Memory plugs in via `RunnableWithMessageHistory`, injecting a `BaseChatMessageHistory` into the chain before each LLM call using `input_messages_key` and `history_messages_key` — no manual prompt surgery. For production, prefer `chain.stream()` over `.invoke()` to forward OpenAI's token-level SSE stream directly to your client. Set `langchain.debug = True` to inspect every Runnable's input/output, including the raw payload sent to OpenAI's `/v1/chat/completions`. LCEL makes OpenAI's full feature surface — streaming, function calling, structured outputs via `with_structured_output()` — composable without boilerplate.$escape$,
  $escape$from langchain_openai import ChatOpenAI
from langchain_core.prompts import ChatPromptTemplate
from langchain_core.output_parsers import StrOutputParser
from langchain_core.tools import tool
from langchain.agents import AgentExecutor, create_tool_calling_agent

llm = ChatOpenAI(model="gpt-4o", temperature=0)

@tool
def get_weather(city: str) -> str:
    """Fetch current weather for a city."""
    return f"Sunny, 22°C in {city}"

prompt = ChatPromptTemplate.from_messages([
    ("system", "You are a helpful assistant."),
    ("placeholder", "{chat_history}"),
    ("human", "{input}"),
    ("placeholder", "{agent_scratchpad}"),
])

agent = create_tool_calling_agent(llm, [get_weather], prompt)
executor = AgentExecutor(agent=agent, tools=[get_weather], verbose=True)
print(executor.invoke({"input": "Weather in Tokyo?", "chat_history": []}))$escape$,
  $escape$python$escape$,
