INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c8734c70-e400-4b69-b6cc-67b04d264116',
  '00000000-0000-0000-0000-000000000001',
  $escape$OpenAI API + LlamaIndex — Embeddings, Indexes, and Query Engines That Actually Scale$escape$,
  $escape$LlamaIndex wires directly into OpenAI API's embedding and chat completion endpoints. By default, `VectorStoreIndex` uses `text-embedding-ada-002` to chunk and embed documents, then routes queries through `gpt-3.5-turbo`. Override both via `Settings` to use `text-embedding-3-large` (3072-dim) and `gpt-4o` for production-grade RAG. Document loading starts with `SimpleDirectoryReader`, which handles PDF, Markdown, and plain text automatically. Once loaded, `VectorStoreIndex.from_documents()` chunks each node at 1024 tokens with 20-token overlap by default — tune this with `SentenceSplitter(chunk_size=512, chunk_overlap=50)` for precision-sensitive domains. The query engine returned by `as_query_engine()` internally calls `/v1/embeddings` on the question, retrieves top-k nodes by cosine similarity, then calls `/v1/chat/completions` with a stuffed context prompt. Bump `similarity_top_k=10` when recall matters more than latency. For hybrid search, swap in `VectorStoreIndex` backed by `PineconeVectorStore` or `QdrantVectorStore` and keep the same OpenAI API calls — LlamaIndex abstracts the store, not the model.$escape$,
  $escape$from llama_index.core import VectorStoreIndex, SimpleDirectoryReader, Settings
from llama_index.core.node_parser import SentenceSplitter
from llama_index.llms.openai import OpenAI
from llama_index.embeddings.openai import OpenAIEmbedding

Settings.llm = OpenAI(model="gpt-4o", temperature=0.1)
Settings.embed_model = OpenAIEmbedding(model="text-embedding-3-large")
Settings.node_parser = SentenceSplitter(chunk_size=512, chunk_overlap=50)

docs = SimpleDirectoryReader("./docs").load_data()
index = VectorStoreIndex.from_documents(docs)

query_engine = index.as_query_engine(similarity_top_k=8)
response = query_engine.query("How does the retry logic work?")
print(response)$escape$,
  $escape$python$escape$,
