INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '62946cb8-5260-4ea9-a8c0-c10bc917b71d',
  '00000000-0000-0000-0000-000000000001',
  $escape$OpenAI API RAG Pipeline — Chunking, Embeddings, and Reranking That Actually Works$escape$,
  $escape$Most RAG failures happen before retrieval ever runs. Start with recursive character splitting at 512 tokens with 64-token overlap using LangChain's `RecursiveCharacterTextSplitter` or a custom implementation — this preserves sentence boundaries better than fixed splits. Feed chunks to `text-embedding-3-large` (3072 dims) via `openai.embeddings.create()` with `model="text-embedding-3-large"`. Store in pgvector with an HNSW index for sub-10ms ANN search at scale.

Retrieval alone isn't enough. Over-fetch — pull top-20 candidates — then rerank using a cross-encoder pattern: pass each `(query, chunk)` pair to `gpt-4o-mini` with a scoring prompt and sort by returned score. This two-stage approach costs ~$0.002 per query but measurably improves answer grounding.

For embedding calls, batch up to 2048 inputs per request to stay within rate limits. Use `dimensions` parameter on `text-embedding-3-large` to compress to 1024 dims if storage is a constraint — OpenAI's Matryoshka training means quality degrades gracefully. Always normalize vectors before cosine similarity to avoid magnitude bias in retrieval.$escape$,
  $escape$import openai

client = openai.OpenAI()

def embed_chunks(chunks: list[str], dims: int = 1024) -> list[list[float]]:
    response = client.embeddings.create(
        model="text-embedding-3-large",
        input=chunks,
        dimensions=dims,
        encoding_format="float",
    )
    return [item.embedding for item in response.data]

def rerank(query: str, candidates: list[str], top_k: int = 5) -> list[str]:
    scores = []
    for chunk in candidates:
        resp = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=[{"role": "user", "content": f"Score relevance 0-10.\nQuery: {query}\nChunk: {chunk}\nReturn only a number."}],
            max_tokens=3,
        )
        scores.append((float(resp.choices[0].message.content.strip()), chunk))
    return [c for _, c in sorted(scores, reverse=True)[:top_k]]$escape$,
  $escape$python$escape$,
