INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b42e0fdc-2932-4f49-98cd-2ea6bcc1b540',
  '00000000-0000-0000-0000-000000000001',
  $escape$OpenAI API — Structured Outputs with response_format and Strict Function Schemas$escape$,
  $escape$Since late 2024, the OpenAI API guarantees JSON conformance via `response_format: { type: 'json_schema', json_schema: { strict: true, schema: ... } }` on `gpt-4o` and `gpt-4o-mini`. Unlike the older `json_object` mode, strict schemas enforce exact field presence — no hallucinated keys, no missing required fields. This pairs with function calling: set `strict: true` inside your tool definition and the model is constrained to emit only valid arguments matching your JSON Schema.

For embeddings, `text-embedding-3-small` (1536-dim) and `text-embedding-3-large` (3072-dim) both support dimension reduction via the `dimensions` parameter — pass `dimensions: 256` to get a truncated but still high-quality vector, cutting storage and cosine-search cost significantly. Combine this with structured outputs for a RAG pipeline where retrieved chunks are summarized into a typed response object. The key shift: treat the API as a typed function call, not a string generator. Validate schemas upfront with Zod or Pydantic so schema mismatches surface at dev time, not in prod.$escape$,
  $escape$import OpenAI from 'openai';
import { z } from 'zod';
import { zodResponseFormat } from 'openai/helpers/zod';

const client = new OpenAI();

const ArticleSummary = z.object({
  headline: z.string(),
  key_points: z.array(z.string()).max(3),
  sentiment: z.enum(['positive', 'neutral', 'negative']),
});

const response = await client.beta.chat.completions.parse({
  model: 'gpt-4o-mini',
  messages: [{ role: 'user', content: 'Summarize: OpenAI launches o3 model with reasoning.' }],
  response_format: zodResponseFormat(ArticleSummary, 'article_summary'),
});

const summary = response.choices[0].message.parsed;
console.log(summary.headline, summary.sentiment);$escape$,
  $escape$typescript$escape$,
