INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f7ed93f3-ad36-48d2-8acb-7783296f1ebc',
  '00000000-0000-0000-0000-000000000001',
  $escape$openai_api → Anthropic API: Claude Models, Tool Use, and Streaming Differences That Will Bite You$escape$,
  $escape$Switching from the OpenAI SDK to Anthropic's feels familiar but has sharp edges. The system prompt leaves the messages array entirely — it's a top-level `system` string parameter on `client.messages.create()`. Passing it as `{"role": "system", ...}` inside messages raises a validation error. Tool definitions swap `parameters` for `input_schema`, keeping the same JSON Schema structure underneath. Responses return a typed `content` list instead of `choices[0].message.content` — iterate blocks and check `block.type == "tool_use"` to detect function calls. Returning tool results requires a user-role message containing a `tool_result` content block with the matching `tool_use_id` — more explicit than OpenAI's flat `tool_call_id` field. For streaming, use the `with client.messages.stream() as stream:` context manager; `stream.text_stream` is an async-compatible generator of raw text deltas, equivalent to `chunk.choices[0].delta.content`. Model naming follows `claude-<family>-<version>` — current production choices are `claude-opus-4-5` and `claude-sonnet-4-5`. Install with `pip install anthropic`.$escape$,
  $escape$import anthropic

client = anthropic.Anthropic()

response = client.messages.create(
    model="claude-opus-4-5",
    max_tokens=1024,
    system="You are a concise assistant.",  # NOT inside messages[]
    tools=[{
        "name": "get_weather",
        "description": "Get current weather for a location.",
        "input_schema": {           # 'input_schema', not 'parameters'
            "type": "object",
            "properties": {"location": {"type": "string"}},
            "required": ["location"]
        }
    }],
    messages=[{"role": "user", "content": "What's the weather in Austin?"}]
)

for block in response.content:      # not choices[0].message
    if block.type == "tool_use":
        print(block.name, block.input)  # {'location': 'Austin'}
$escape$,
  $escape$python$escape$,
