INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7b401e9d-627c-478f-aa01-60bbd3eb20d2',
  '00000000-0000-0000-0000-000000000001',
  $escape$openai_api + Groq — Drop-In Speed Upgrade with Zero SDK Changes$escape$,
  $escape$Groq exposes an OpenAI-compatible REST API, meaning you can redirect the OpenAI Python SDK to Groq's inference endpoint by changing two lines: `base_url` and `api_key`. No new SDK, no refactored call sites. Groq's LPU (Language Processing Unit) delivers dramatically lower time-to-first-token — often 10–20x faster than hosted GPU inference — making it viable for latency-sensitive apps like streaming chat or real-time code assistance.

Groq supports `llama-3.3-70b-versatile`, `llama-3.1-8b-instant`, `mixtral-8x7b-32768`, and `gemma2-9b-it` as of early 2026. The `model` string is the only breaking change from your existing OpenAI call. Chat completions, streaming, system prompts, and `response_format` (including `json_object`) all work identically. Function calling is supported on Llama 3.3 70B.

One caveat: Groq enforces strict rate limits on the free tier (tokens per minute, not requests), so production use requires a paid plan. Context windows vary by model — `mixtral-8x7b-32768` offers 32K, while `llama-3.1-8b-instant` caps at 128K.$escape$,
  $escape$from openai import OpenAI

client = OpenAI(
    api_key="gsk_YOUR_GROQ_API_KEY",
    base_url="https://api.groq.com/openai/v1",
)

stream = client.chat.completions.create(
    model="llama-3.3-70b-versatile",
    messages=[{"role": "user", "content": "Explain RLHF in 2 sentences."}],
    stream=True,
)

for chunk in stream:
    print(chunk.choices[0].delta.content or "", end="", flush=True)$escape$,
  $escape$python$escape$,
