INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4cd186a1-9fb0-42d6-b477-f6d5b0a4bba9',
  '00000000-0000-0000-0000-000000000001',
  $escape$openai_api + Ollama — Drop-in Local Inference, Zero Data Leakage$escape$,
  $escape$Ollama exposes an OpenAI-compatible REST endpoint at `http://localhost:11434/v1`, meaning you can swap your `OpenAI` client to hit it with a single constructor change — no new SDK, no refactored call sites. Pull a model with `ollama pull llama3.2`, then point the client at the local base URL. Every method you already use — `chat.completions.create`, streaming with `stream=True`, structured outputs via `response_format` — works identically against Ollama's runtime.

The privacy benefit is concrete: tokens never leave your machine. Useful for processing internal codebases, proprietary docs, or PII-heavy workflows where sending data to `api.openai.com` is a compliance risk. The model library covers Llama 3.2, Mistral, Gemma 2, Phi-3, DeepSeek, and others — each versioned and cached locally under `~/.ollama/models`.

Latency is GPU-bound. On Apple Silicon with Metal, a 7B model at 4-bit quantization hits ~50 tok/s — fast enough for interactive tooling. Use the same `base_url` swap in CI to avoid API costs during integration tests.$escape$,
  $escape$from openai import OpenAI

client = OpenAI(
    base_url="http://localhost:11434/v1",
    api_key="ollama",  # required by SDK, value ignored by Ollama
)

stream = client.chat.completions.create(
    model="llama3.2",
    messages=[{"role": "user", "content": "Summarize this PR diff: ..."}],
    stream=True,
)

for chunk in stream:
    print(chunk.choices[0].delta.content or "", end="", flush=True)$escape$,
  $escape$python$escape$,
