INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '85dcd7b6-c9af-468d-80ab-b1f1bff2cb20',
  '00000000-0000-0000-0000-000000000001',
  $escape$OpenAI API Embeddings — Choosing Models and Measuring Semantic Similarity$escape$,
  $escape$OpenAI's Embeddings API turns text into dense float vectors you can compare with cosine similarity. The current production model is `text-embedding-3-large` (3072 dims) — but `text-embedding-3-small` (1536 dims) is 5× cheaper and within 3–5% accuracy on most retrieval benchmarks. Both support the `dimensions` parameter to truncate output without retraining, so you can emit 256-dim vectors from `text-embedding-3-large` for low-latency nearest-neighbor search while retaining model quality. The older `text-embedding-ada-002` (1536 dims) is still widely deployed but has no dimension control and lags both v3 models on MTEB.

For semantic similarity, compute cosine similarity directly on the raw vectors — OpenAI normalizes outputs to unit length, so `dot(a, b)` equals cosine similarity with no extra math. Store embeddings in pgvector with `vector(1536)` or `vector(3072)` columns and use `<=>` (cosine distance) for ANN queries. Batch up to 2048 inputs per request to maximize throughput and minimize round-trips.$escape$,
  $escape$import openai
import numpy as np

client = openai.OpenAI()

def embed(texts: list[str], dims: int = 512) -> list[list[float]]:
    response = client.embeddings.create(
        model="text-embedding-3-large",
        input=texts,
        dimensions=dims,
    )
    return [d.embedding for d in response.data]

def cosine_similarity(a: list[float], b: list[float]) -> float:
    va, vb = np.array(a), np.array(b)
    return float(np.dot(va, vb))  # already unit-normalized

vecs = embed(["pgvector ANN index", "approximate nearest neighbor in Postgres"])
print(cosine_similarity(vecs[0], vecs[1]))  # ~0.91$escape$,
  $escape$python$escape$,
