INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '70b6183c-d436-49b4-8022-74a4dc82c5f6',
  '00000000-0000-0000-0000-000000000001',
  $escape$openai_api Fine-Tuning — When to Stop Prompt Engineering and Train Instead$escape$,
  $escape$Fine-tuning via OpenAI's API earns its cost in three specific cases: your system prompt plus few-shot examples exceed 2k tokens per call (burning money on every request), you need output consistency that prompt engineering can't reliably enforce across temperature variance, or you're collapsing a complex chain-of-thought into a single fast call. For knowledge injection or grounding, RAG still wins—fine-tuning doesn't memorize facts reliably.

OpenAI's `client.fine_tuning.jobs.create` runs LoRA (Low-Rank Adaptation) internally: small adapter matrices are trained on top of frozen base weights. Training 500 examples on `gpt-4o-mini-2024-07-18` takes ~15 minutes and costs roughly $0.30. You don't control LoRA rank or alpha—OpenAI abstracts that entirely. QLoRA (quantized LoRA via bitsandbytes + PEFT) is a self-hosted technique; it has no surface in the OpenAI API.

Training data is JSONL—each line mirrors the chat completions format exactly: `{"messages": [{"role": "system", ...}, {"role": "user", ...}, {"role": "assistant", ...}]}`. Target 50–500 high-quality examples. Monitor `validation_loss` via job events; divergence from `training_loss` signals overfitting. Start with `n_epochs: 3` and cut early if val loss flattens.$escape$,
  $escape$from openai import OpenAI

client = OpenAI()

# Upload JSONL training file
file = client.files.create(
    file=open("training_data.jsonl", "rb"),
    purpose="fine-tune"
)

job = client.fine_tuning.jobs.create(
    training_file=file.id,
    model="gpt-4o-mini-2024-07-18",
    hyperparameters={"n_epochs": 3}
)

# Stream events to watch training_loss vs validation_loss
for event in client.fine_tuning.jobs.list_events(job.id, limit=20).data:
    print(event.message)

# Use the fine-tuned model
response = client.chat.completions.create(
    model=job.fine_tuned_model,
    messages=[{"role": "user", "content": "Classify this ticket: ..."}]
)$escape$,
  $escape$python$escape$,
