INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd50533bf-9462-44fc-94e3-eb19795e5abc',
  '00000000-0000-0000-0000-000000000001',
  $escape$OpenAI API Agents — Building Reliable Tool-Calling Loops with Function Calling$escape$,
  $escape$OpenAI's function calling lets you bind structured tools to a model so it can decide when and how to invoke them. The pattern: define tools in the `tools` array, send a request, check if `finish_reason === 'tool_calls'`, execute the function locally, append the result as a `tool` role message, and loop until `finish_reason === 'stop'`. This is the ReAct pattern made concrete — the model reasons, acts, observes, and continues. Tool selection is automatic: given multiple tools, the model picks based on the user query and tool descriptions, so description quality directly impacts accuracy. Set `tool_choice: 'auto'` for flexible selection, `'required'` to force a call, or pin a specific tool with `{ type: 'function', function: { name: 'get_weather' } }`. For production agent loops, always cap iterations (e.g. max 10 turns) to prevent infinite loops caused by hallucinated tool arguments or missing base cases. Use `parallel_tool_calls: false` when tools have side effects that must be sequenced.$escape$,
  $escape$import OpenAI from 'openai';

const client = new OpenAI();
const tools = [{
  type: 'function' as const,
  function: {
    name: 'get_stock_price',
    description: 'Returns the current stock price for a given ticker symbol.',
    parameters: { type: 'object', properties: { ticker: { type: 'string' } }, required: ['ticker'] },
  },
}];

const messages: OpenAI.Chat.ChatCompletionMessageParam[] = [
  { role: 'user', content: 'What is the price of NVDA?' },
];

for (let i = 0; i < 10; i++) {
  const response = await client.chat.completions.create({ model: 'gpt-4o', tools, messages });
  const choice = response.choices[0];
  if (choice.finish_reason === 'stop') { console.log(choice.message.content); break; }
  const call = choice.message.tool_calls![0];
  const args = JSON.parse(call.function.arguments);
  const result = { price: args.ticker === 'NVDA' ? 875.42 : 0 };
  messages.push(choice.message);
  messages.push({ role: 'tool', tool_call_id: call.id, content: JSON.stringify(result) });
}$escape$,
  $escape$typescript$escape$,
