INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b753e894-3e80-4c6f-8cb8-b7dd7ffca5e0',
  '00000000-0000-0000-0000-000000000001',
  $escape$OpenAI API Streaming — Token-by-Token Output with stream=True$escape$,
  $escape$OpenAI's streaming API uses server-sent events (SSE) to push tokens as they're generated, eliminating the perceived latency of waiting for a full completion. With the Python SDK, pass `stream=True` to `client.chat.completions.create()` — you get back a `Stream[ChatCompletionChunk]` iterator where each chunk contains `delta.content` (a partial string or `None` for the final chunk). The key UX pattern: flush output immediately to the UI on each chunk rather than buffering. For web apps, pipe the SSE stream directly to the browser using `text/event-stream` content type — the frontend's `EventSource` or `fetch` with `ReadableStream` can consume it natively. Watch for two edge cases: `finish_reason == 'length'` signals a truncated response (increase `max_tokens`), and `delta.content` is `None` on the final sentinel chunk, so always guard with `chunk.choices[0].delta.content or ''`. For tool calls, `delta.tool_calls` streams incrementally too — accumulate `function.arguments` across chunks before parsing JSON.$escape$,
  $escape$from openai import OpenAI

client = OpenAI()

stream = client.chat.completions.create(
    model="gpt-4o",
    messages=[{"role": "user", "content": "Explain embeddings in 3 sentences."}],
    stream=True,
)

for chunk in stream:
    delta = chunk.choices[0].delta.content or ""
    print(delta, end="", flush=True)

print()  # newline after stream ends$escape$,
  $escape$python$escape$,
