INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ff9b58b2-8028-4790-9c39-79d9d7adcb91',
  '00000000-0000-0000-0000-000000000001',
  $escape$OpenAI API Cost Management — Token Counting, Caching, and Smart Model Selection$escape$,
  $escape$Every OpenAI API call costs money proportional to tokens consumed. Use `tiktoken` to count tokens before sending requests — `cl100k_base` for GPT-4o and `o200k_base` for o1/o3 models. Prompt caching automatically activates for prompts over 1,024 tokens with repeated prefixes, cutting input costs by 50% (GPT-4o) or 75% (o1). Structure prompts so the static system prompt comes first and dynamic user content comes last — this maximizes cache hits. For batch workloads with no latency requirement, the Batch API cuts costs 50% by processing requests asynchronously within 24 hours. Model selection matters most: GPT-4o-mini handles classification, extraction, and summarization at roughly 15x lower cost than GPT-4o. Use GPT-4o only when reasoning depth or instruction-following complexity demands it. Enable `stream: true` for streaming responses — this doesn't reduce cost but prevents timeout failures on long outputs. Monitor spend via `usage` in every response object: `prompt_tokens`, `completion_tokens`, and the new `prompt_tokens_details.cached_tokens` to verify cache hits.$escape$,
  $escape$import tiktoken
from openai import OpenAI

client = OpenAI()
enc = tiktoken.encoding_for_model("gpt-4o")

system_prompt = "You are a code review assistant..."  # static — cache-friendly prefix
user_message = "Review this PR diff: ..."

tokens_before = len(enc.encode(system_prompt + user_message))
print(f"Estimated input tokens: {tokens_before}")

response = client.chat.completions.create(
    model="gpt-4o-mini",  # 15x cheaper than gpt-4o for extraction tasks
    messages=[
        {"role": "system", "content": system_prompt},
        {"role": "user", "content": user_message}
    ]
)

u = response.usage
print(f"Cached: {u.prompt_tokens_details.cached_tokens} / {u.prompt_tokens} tokens")$escape$,
  $escape$python$escape$,
