INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '250c5385-daf4-46be-a206-07d726e086a9',
  '00000000-0000-0000-0000-000000000001',
  $escape$openai_api — LLM-as-Judge and RAGAS Evaluation for Production RAG Pipelines$escape$,
  $escape$Evaluating RAG outputs with OpenAI API means two complementary layers: LLM-as-judge using GPT-4o's structured outputs, and RAGAS metrics over your retrieval pipeline. For LLM-as-judge, use `response_format` with a Pydantic schema to get deterministic JSON scores — faithfulness, answer relevance, context precision — rather than freeform prose that requires parsing. Pass the original query, retrieved context chunks, and generated answer in the system prompt with an explicit 1–5 rubric. RAGAS integrates natively with OpenAI: set `OPENAI_API_KEY` and it defaults to `gpt-4o` for LLM calls and `text-embedding-3-small` for embeddings. Run `evaluate()` over a `Dataset` of `{question, answer, contexts, ground_truth}` rows to get `context_recall`, `context_precision`, `faithfulness`, and `answer_correctness` as a Pandas DataFrame. For CI regression gates, log scores to a JSONL file per commit and fail the pipeline if `faithfulness < 0.80`. OpenAI's own Evals framework (`openai.evals`) lets you run custom eval suites against any `gpt-4o-*` snapshot with `oaieval` CLI — useful for benchmarking model upgrades before swapping the production pointer.$escape$,
  $escape$from openai import OpenAI
from pydantic import BaseModel

client = OpenAI()

class EvalScore(BaseModel):
    faithfulness: float  # 0.0–1.0
    relevance: float
    reasoning: str

def judge(query: str, context: str, answer: str) -> EvalScore:
    completion = client.beta.chat.completions.parse(
        model="gpt-4o",
        messages=[
            {"role": "system", "content": "Score the answer on faithfulness and relevance (0–1). Use only the provided context."},
            {"role": "user", "content": f"Query: {query}\nContext: {context}\nAnswer: {answer}"},
        ],
        response_format=EvalScore,
    )
    return completion.choices[0].message.parsed$escape$,
  $escape$python$escape$,
