INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '119985f0-73f0-48b6-b560-0bbbf1bbfd17',
  '00000000-0000-0000-0000-000000000001',
  $escape$OpenAI API — Layered Safety: Output Filtering, Prompt Injection Defense, and Hallucination Mitigation$escape$,
  $escape$OpenAI's Moderation API (`omni-moderation-latest`) should be your first line of defense — run both user input and model output through it before rendering anything to users. For prompt injection, never interpolate raw user content into system prompts; instead, delimit it explicitly with XML-style tags (`<user_input>`) and instruct the model to treat that block as untrusted data only. Structured outputs (`response_format: { type: 'json_schema' }`) constrain the model to a validated schema, dramatically reducing hallucinated field names or invented values. For factual grounding, pair `gpt-4o` with retrieval: pass source documents in context and add a system instruction like "Only answer using the provided context. If the answer isn't present, say 'I don't know'." Use `logprobs: true` on completions to inspect token-level confidence — low log-probability tokens on key facts are a hallucination signal worth flagging or re-querying. Chain these layers: moderate input → structured output → logprob audit → moderate output.$escape$,
  $escape$import OpenAI from 'openai';

const client = new OpenAI();

async function safeCompletion(userMessage: string, context: string) {
  const modInput = await client.moderations.create({ model: 'omni-moderation-latest', input: userMessage });
  if (modInput.results[0].flagged) throw new Error('Input flagged by moderation');

  const completion = await client.chat.completions.create({
    model: 'gpt-4o',
    logprobs: true,
    response_format: { type: 'json_schema', json_schema: { name: 'answer', strict: true, schema: { type: 'object', properties: { answer: { type: 'string' }, confident: { type: 'boolean' } }, required: ['answer', 'confident'], additionalProperties: false } } },
    messages: [
      { role: 'system', content: `Answer using only the context below. If unsure, set confident=false.\n<context>${context}</context>` },
      { role: 'user', content: `<user_input>${userMessage}</user_input>` }
    ]
  });

  const modOutput = await client.moderations.create({ model: 'omni-moderation-latest', input: completion.choices[0].message.content! });
  if (modOutput.results[0].flagged) throw new Error('Output flagged by moderation');

  return JSON.parse(completion.choices[0].message.content!);
}
$escape$,
